                                     (r0 + r1) / 255.0f)
                                            .cast<double>());
                        } else if (color_type_ ==
                                   TSDFVolumeColorType::Gray32) {
                            pointcloud->colors_.push_back(
                                    ((c0 * r1 + c1 * r0) /
                                     (r0 + r1))
                                            .cast<double>());
                        }
                        // has_normal
                        pointcloud->normals_.push_back(
                                GetNormalAt(p));
                    }
                }
            }
        }
    }
}

